# Utility module for geometric calculations
from colors import Color, mix_colors
from shapes import Shape, ShapeType

struct Point:
    """2D coordinate struct"""
    _x: float
    _y: float

    def __init__(self, x: float, y: float):
        self._x = x
        self._y = y

    @property
    get x(self) -> float:
        return self._x

    @property
    get y(self) -> float:
        return self._y

    def distance_to(self, other: Point) -> float:
        """Calculate Euclidean distance to another point"""
        dx: float = self._x - other.x
        dy: float = self._y - other.y
        return (dx * dx + dy * dy) ** 0.5

    def __str__(self) -> str:
        return f"Point({self._x:.2f},{self._y:.2f})"

class ShapeUtils:
    """Static utility methods for shape operations"""

    def create_midpoint(p1: Point, p2: Point) -> Point:
        """Create point at the midpoint of two points"""
        return Point((p1.x + p2.x) / 2.0, (p1.y + p2.y) / 2.0)

    def blend_shape_colors(s1: Shape, s2: Shape) -> Color:
        """Mix colors of two shapes"""
        c1: Color = s1.get_color()
        c2: Color = s2.get_color()
        return mix_colors(c1, c2)

