# Extended shapes module - concrete shape implementations
from shapes import Shape, ShapeType, IShape
from colors import Color
from utils import Point

PI: float = 3.14159

class Rectangle(Shape):
    """Rectangle shape extending cross-module base class"""
    _width: float
    _height: float
    _top_left: Point

    def __init__(self, w: float, h: float, c: Color, tl: Point):
        super().__init__(ShapeType.RECTANGLE, c)
        self._width = w
        self._height = h
        self._top_left = tl

    @property
    get width(self) -> float:
        return self._width

    @property
    get height(self) -> float:
        return self._height

    @override
    def area(self) -> float:
        return self._width * self._height

    @override
    def perimeter(self) -> float:
        return 2.0 * (self._width + self._height)

    @override
    def description(self) -> str:
        return f"Rectangle {self._width}x{self._height}"

    def __str__(self) -> str:
        return f"Rectangle({self._width},{self._height})"

class Circle(Shape):
    """Circle shape extending cross-module base class"""
    _radius: float
    _center: Point

    def __init__(self, r: float, c: Color, center: Point):
        super().__init__(ShapeType.CIRCLE, c)
        self._radius = r
        self._center = center

    @property
    get radius(self) -> float:
        return self._radius

    @override
    def area(self) -> float:
        return PI * self._radius * self._radius

    @override
    def perimeter(self) -> float:
        return 2.0 * PI * self._radius

    @override
    def description(self) -> str:
        return f"Circle r={self._radius}"

    def contains_point(self, p: Point) -> bool:
        """Check if point lies within the circle"""
        return self._center.distance_to(p) <= self._radius
